// @ts-nocheck
// Converte base64 de áudio para binary para o node OpenAI Whisper
const trigger = $('EXECUTE WORKFLOW TRIGGER').item.json;
const b64response = $json;

const b64 = b64response.base64 || b64response.data || b64response.audio || null;

if (!b64) {
  return {
    json: {
      audio_binary: null,
      audio_b64_missing: true,
      agent_note: 'AUDIO_DOWNLOAD_FAILED'
    },
    binary: {}
  };
}

const mimeType = b64response.mimetype || 'audio/ogg';
const ext = mimeType.includes('mp4') ? 'mp4' : mimeType.includes('mpeg') ? 'mp3' : 'ogg';
const filename = `audio_${Date.now()}.${ext}`;

return {
  json: {
    audio_binary: true,
    audio_b64_missing: false,
    filename: filename,
    mimetype: mimeType
  },
  binary: {
    data: {
      data: b64,
      mimeType: mimeType,
      fileName: filename,
      fileExtension: ext
    }
  }
};

// @ts-nocheck
// Merge do resultado de transcrição de áudio
const prev = $('CODE: AUDIO B64 TO BINARY').item.json;

if (prev.audio_b64_missing) {
  return {
    json: {
      media_ok: false,
      transcription: null,
      visual_description: null,
      fallback_message: 'Recebi seu áudio, mas não consegui processá-lo agora. Pode digitar sua mensagem?',
      agent_note: 'AUDIO_DOWNLOAD_FAILED'
    }
  };
}

const text = $json.text || $json.transcription || null;

if (!text) {
  return {
    json: {
      media_ok: false,
      transcription: null,
      visual_description: null,
      fallback_message: 'Recebi seu áudio, mas não consegui transcrever. Pode digitar sua mensagem?',
      agent_note: 'AUDIO_TRANSCRIPTION_EMPTY'
    }
  };
}

return {
  json: {
    media_ok: true,
    transcription: text.trim(),
    visual_description: null,
    fallback_message: null,
    agent_note: null
  }
};

// @ts-nocheck
// Prepara data URL da imagem para Vision (OpenRouter)
const trigger = $('EXECUTE WORKFLOW TRIGGER').item.json;
const b64response = $json;

const b64 = b64response.base64 || b64response.data || null;
const mimeType = b64response.mimetype || 'image/jpeg';

let imageUrl = trigger.media_url || null;
let usingBase64 = false;

if (b64) {
  imageUrl = `data:${mimeType};base64,${b64}`;
  usingBase64 = true;
} else if (!imageUrl) {
  return {
    json: {
      image_data_url: null,
      image_missing: true,
      agent_note: 'IMAGE_DOWNLOAD_FAILED'
    }
  };
}

return {
  json: {
    image_data_url: imageUrl,
    image_missing: false,
    using_base64: usingBase64,
    caption: trigger.message_text || ''
  }
};

