// @ts-nocheck
// Merge do resultado de análise de imagem Vision
const prepData = $('CODE: PREP IMAGE DATA URL').item.json;

if (prepData.image_missing) {
  return {
    json: {
      media_ok: false,
      transcription: null,
      visual_description: null,
      fallback_message: 'Recebi sua imagem, mas não consegui visualizá-la. Pode descrever o que procura?',
      agent_note: 'IMAGE_DOWNLOAD_FAILED'
    }
  };
}

const choices = $json.choices || [];
const content = choices[0]?.message?.content || '';

if (!content) {
  return {
    json: {
      media_ok: false,
      transcription: null,
      visual_description: null,
      fallback_message: 'Recebi sua imagem, mas não consegui analisá-la. Pode descrever o que procura?',
      agent_note: 'IMAGE_VISION_EMPTY'
    }
  };
}

const isPaymentReceipt = content.includes('[COMPROVANTE_PAGAMENTO]');
const isFloralRef = content.includes('[REFERENCIA_FLORAL]');
const isPlant = content.includes('[PLANTA]');

let agentNote = 'IMAGE_OTHER';
if (isPaymentReceipt) agentNote = 'PAYMENT_RECEIPT';
else if (isFloralRef) agentNote = 'IMAGE_REFERENCE';
else if (isPlant) agentNote = 'PLANT_REFERENCE';

return {
  json: {
    media_ok: true,
    transcription: null,
    visual_description: content.trim(),
    is_payment_receipt: isPaymentReceipt,
    is_floral_reference: isFloralRef,
    fallback_message: null,
    agent_note: agentNote
  }
};
